var COURSE_NL_PL = [{day: 1, title: `Begroeten en beleefd beginnen`, title_native: `Powitania i grzeczny początek`, focus: `Je begint met de eerste woorden die je in Warschau, Krakau of Gdańsk meteen nodig hebt. Vandaag oefen je begroeten, afscheid nemen en beleefd reageren.`, vocab: [{pl: `dzień dobry`, nl: `goedendag`, ipa: `djen DO-bri`},{pl: `cześć`, nl: `hallo / hoi`, ipa: `tsjesjtsj`},{pl: `dobry wieczór`, nl: `goedenavond`, ipa: `DO-bri VYE-tsjoer`},{pl: `do widzenia`, nl: `tot ziens`, ipa: `do vee-DZEN-ja`},{pl: `proszę`, nl: `alstublieft / graag`, ipa: `PRO-sje`},{pl: `dziękuję`, nl: `dank u / dank je`, ipa: `djen-KOO-ye`},{pl: `tak`, nl: `ja`, ipa: `tak`},{pl: `nie`, nl: `nee`, ipa: `nye`},{pl: `przepraszam`, nl: `sorry / pardon`, ipa: `pshe-PRA-sham`},{pl: `pan`, nl: `meneer / u`, ipa: `pan`}], phrases: [{pl: `Dzień dobry.`, nl: `Goedendag.`, ipa: `djen DO-bri`},{pl: `Cześć, jak się masz?`, nl: `Hoi, hoe gaat het?`, ipa: `tsjesjtsj yak shen mash`},{pl: `Dziękuję bardzo.`, nl: `Hartelijk dank.`, ipa: `djen-KOO-ye BAR-dzo`},{pl: `Przepraszam.`, nl: `Pardon.`, ipa: `pshe-PRA-sham`},{pl: `Do widzenia.`, nl: `Tot ziens.`, ipa: `do vee-DZEN-ja`},{pl: `Tak, proszę.`, nl: `Ja, graag.`, ipa: `tak PRO-sje`}], grammar: `In het Pools gebruik je vaak beleefde vormen, vooral met mensen die je niet kent. “Pan” betekent meneer of u voor een man, en “pani” betekent mevrouw of u voor een vrouw. “Proszę” is een heel handig woord: het kan “alstublieft”, “graag” of “gaat uw gang” betekenen, afhankelijk van de situatie.`, practice: [`Groet een hotelmedewerker in het Pools.`,`Zeg “dank u wel” op twee manieren.`,`Oefen het verschil tussen “cześć” en “dzień dobry”.`,`Maak een korte beleefde zin met “proszę”.`,`Sluit een gesprek af met “do widzenia”.`]},{day: 2, title: `Jezelf voorstellen`, title_native: `Przedstawianie się`, focus: `In Poznań ontmoet je iemand in een hostel of café en wil je jezelf kort voorstellen. Je leert zeggen wie je bent, waar je vandaan komt en dat je Nederlands spreekt.`, vocab: [{pl: `nazywam się`, nl: `ik heet`, ipa: `na-ZI-vam shen`},{pl: `jestem`, nl: `ik ben`, ipa: `YES-tem`},{pl: `Holandia`, nl: `Nederland`, ipa: `ho-LAN-dja`},{pl: `Belgia`, nl: `België`, ipa: `BEL-gja`},{pl: `z`, nl: `uit / van`, ipa: `z`},{pl: `turysta`, nl: `toerist`, ipa: `too-RIS-ta`},{pl: `turystka`, nl: `toeriste`, ipa: `too-RIS-tka`},{pl: `miło`, nl: `prettig / leuk`, ipa: `MEE-wo`},{pl: `język`, nl: `taal`, ipa: `YEN-zik`},{pl: `niderlandzki`, nl: `Nederlands`, ipa: `nee-der-LANT-ski`}], phrases: [{pl: `Nazywam się Anna.`, nl: `Ik heet Anna.`, ipa: `na-ZI-vam shen AN-na`},{pl: `Jestem z Holandii.`, nl: `Ik kom uit Nederland.`, ipa: `YES-tem z ho-LAN-dji`},{pl: `Jestem turystą.`, nl: `Ik ben een toerist.`, ipa: `YES-tem too-RIS-tom`},{pl: `Jestem turystką.`, nl: `Ik ben een toeriste.`, ipa: `YES-tem too-RIS-tkom`},{pl: `Miło mi.`, nl: `Aangenaam.`, ipa: `MEE-wo mee`},{pl: `Mówię po niderlandzku.`, nl: `Ik spreek Nederlands.`, ipa: `MOO-vye po nee-der-LANT-skoo`}], grammar: `Voor “ik kom uit” gebruik je in het Pools vaak “jestem z” plus het land in een speciale vorm. “Holandia” wordt “z Holandii”. Poolse zelfstandige naamwoorden veranderen vaak van vorm, maar als reiziger kun je vaste zinnen leren en meteen gebruiken.`, practice: [`Zeg je naam met “Nazywam się”.`,`Zeg dat je uit Nederland of België komt.`,`Kies de juiste vorm: “turysta” of “turystka”.`,`Stel jezelf voor in drie korte Poolse zinnen.`,`Reageer op iemand met “Miło mi”.`]},{day: 3, title: `Essentiële vragen`, title_native: `Podstawowe pytania`, focus: `In het centrum van Wrocław moet je snel simpele vragen kunnen stellen. Vandaag leer je vraagwoorden en korte reizigersvragen.`, vocab: [{pl: `kto`, nl: `wie`, ipa: `kto`},{pl: `co`, nl: `wat`, ipa: `tso`},{pl: `gdzie`, nl: `waar`, ipa: `gdje`},{pl: `kiedy`, nl: `wanneer`, ipa: `KYEN-di`},{pl: `ile`, nl: `hoeveel`, ipa: `EE-le`},{pl: `jak`, nl: `hoe`, ipa: `yak`},{pl: `dlaczego`, nl: `waarom`, ipa: `dla-CHE-go`},{pl: `to`, nl: `dit / dat / het`, ipa: `to`},{pl: `tutaj`, nl: `hier`, ipa: `TOO-tay`},{pl: `tam`, nl: `daar`, ipa: `tam`}], phrases: [{pl: `Co to jest?`, nl: `Wat is dit?`, ipa: `tso to yest`},{pl: `Gdzie to jest?`, nl: `Waar is dat?`, ipa: `gdje to yest`},{pl: `Ile to kosztuje?`, nl: `Hoeveel kost dit?`, ipa: `EE-le to kosh-TOO-ye`},{pl: `Jak się nazywa?`, nl: `Hoe heet het?`, ipa: `yak shen na-ZI-va`},{pl: `Czy to jest tutaj?`, nl: `Is het hier?`, ipa: `tshi to yest TOO-tay`},{pl: `Kiedy otwarte?`, nl: `Wanneer is het open?`, ipa: `KYEN-di ot-FAR-te`}], grammar: `Poolse ja/nee-vragen beginnen vaak met “czy”, maar in gesproken taal wordt het soms weggelaten. “Czy to jest tutaj?” betekent letterlijk “Of dit is hier?” en klinkt netjes. Voor reizigers is “gdzie”, “ile” en “czy” extreem nuttig.`, practice: [`Vraag waar iets is met “Gdzie”.`,`Vraag hoeveel iets kost.`,`Maak een ja/nee-vraag met “Czy”.`,`Wijs naar iets en vraag “Co to jest?”.`,`Gebruik “tutaj” en “tam” in twee korte zinnen.`]},{day: 4, title: `Getallen en prijzen`, title_native: `Liczby i ceny`, focus: `Op een markt in Krakau moet je prijzen begrijpen en kleine bedragen kunnen zeggen. Je leert tellen en vragen naar kosten.`, vocab: [{pl: `jeden`, nl: `één`, ipa: `YE-den`},{pl: `dwa`, nl: `twee`, ipa: `dva`},{pl: `trzy`, nl: `drie`, ipa: `tshi`},{pl: `cztery`, nl: `vier`, ipa: `CHTE-ri`},{pl: `pięć`, nl: `vijf`, ipa: `pyentsj`},{pl: `sześć`, nl: `zes`, ipa: `sheshch`},{pl: `siedem`, nl: `zeven`, ipa: `SHYE-dem`},{pl: `osiem`, nl: `acht`, ipa: `O-shyem`},{pl: `dziewięć`, nl: `negen`, ipa: `DJE-vyentsj`},{pl: `dziesięć`, nl: `tien`, ipa: `DJE-shyentsj`}], phrases: [{pl: `Poproszę jeden bilet.`, nl: `Ik wil graag één ticket.`, ipa: `po-PRO-she YE-den BEE-let`},{pl: `Dwa razy, proszę.`, nl: `Twee keer, alstublieft.`, ipa: `dva RA-zi PRO-she`},{pl: `Ile kosztuje?`, nl: `Hoeveel kost het?`, ipa: `EE-le kosh-TOO-ye`},{pl: `To kosztuje pięć złotych.`, nl: `Dat kost vijf zloty.`, ipa: `to kosh-TOO-ye pyentsj ZWO-tih`},{pl: `Mam dziesięć złotych.`, nl: `Ik heb tien zloty.`, ipa: `mam DJE-shyentsj ZWO-tih`},{pl: `Czy mogę zapłacić kartą?`, nl: `Kan ik met kaart betalen?`, ipa: `tshi MO-ge za-PWA-chits KAR-tom`}], grammar: `De Poolse munt is “złoty”. Na sommige getallen verandert de vorm: “jeden złoty”, maar “pięć złotych”. Als reiziger hoef je niet alle regels te beheersen; leer vaste prijszinnen en luister naar het getal.`, practice: [`Tel hardop van één tot tien in het Pools.`,`Vraag hoeveel iets kost.`,`Bestel één ticket.`,`Zeg dat iets vijf zloty kost.`,`Vraag of je met kaart kunt betalen.`]},{day: 5, title: `Beleefd bestellen`, title_native: `Grzeczne zamawianie`, focus: `In een café in Łódź bestel je koffie, water en iets kleins te eten. Je oefent de handige structuur “Poproszę...”.`, vocab: [{pl: `kawa`, nl: `koffie`, ipa: `KA-va`},{pl: `herbata`, nl: `thee`, ipa: `her-BA-ta`},{pl: `woda`, nl: `water`, ipa: `VO-da`},{pl: `mleko`, nl: `melk`, ipa: `MLE-ko`},{pl: `cukier`, nl: `suiker`, ipa: `TSOO-kyer`},{pl: `kanapka`, nl: `broodje`, ipa: `ka-NAP-ka`},{pl: `ciastko`, nl: `koekje / gebakje`, ipa: `CHAST-ko`},{pl: `rachunek`, nl: `rekening`, ipa: `ra-HOO-nek`},{pl: `mały`, nl: `klein`, ipa: `MA-wi`},{pl: `duży`, nl: `groot`, ipa: `DOO-zhi`}], phrases: [{pl: `Poproszę kawę.`, nl: `Ik wil graag koffie.`, ipa: `po-PRO-she KA-ve`},{pl: `Poproszę wodę.`, nl: `Ik wil graag water.`, ipa: `po-PRO-she VO-de`},{pl: `Czy jest mleko?`, nl: `Is er melk?`, ipa: `tshi yest MLE-ko`},{pl: `Bez cukru, proszę.`, nl: `Zonder suiker, alstublieft.`, ipa: `bez TSOO-kroo PRO-she`},{pl: `Poproszę rachunek.`, nl: `De rekening, alstublieft.`, ipa: `po-PRO-she ra-HOO-nek`},{pl: `Na miejscu czy na wynos?`, nl: `Hier of om mee te nemen?`, ipa: `na MYES-tsu tshi na VI-nos`}], grammar: `“Poproszę” is de veiligste manier om iets te bestellen. Het betekent ongeveer “ik zou graag willen”. Daarna verandert het woord soms van vorm, zoals “kawa” naar “kawę”, maar mensen begrijpen je ook als je langzaam en duidelijk spreekt.`, practice: [`Bestel koffie met “Poproszę”.`,`Vraag om water zonder suiker.`,`Vraag naar melk.`,`Vraag om de rekening.`,`Oefen de keuze: “na miejscu” of “na wynos”.`]},{day: 6, title: `Dagen, tijden en openingstijden`, title_native: `Dni, godziny i godziny otwarcia`, focus: `In Gdańsk wil je weten wanneer een museum open is en hoe laat een rondleiding begint. Je leert dagen en eenvoudige tijdzinnen.`, vocab: [{pl: `dzisiaj`, nl: `vandaag`, ipa: `DJEE-shay`},{pl: `jutro`, nl: `morgen`, ipa: `YOO-tro`},{pl: `wczoraj`, nl: `gisteren`, ipa: `FCHO-ray`},{pl: `poniedziałek`, nl: `maandag`, ipa: `po-nye-DJA-wek`},{pl: `wtorek`, nl: `dinsdag`, ipa: `FTO-rek`},{pl: `środa`, nl: `woensdag`, ipa: `SHRO-da`},{pl: `czwartek`, nl: `donderdag`, ipa: `CHVAR-tek`},{pl: `piątek`, nl: `vrijdag`, ipa: `PYON-tek`},{pl: `sobota`, nl: `zaterdag`, ipa: `so-BO-ta`},{pl: `niedziela`, nl: `zondag`, ipa: `nye-DJE-la`}], phrases: [{pl: `Która godzina?`, nl: `Hoe laat is het?`, ipa: `KTOO-ra go-DJEE-na`},{pl: `O której otwarte?`, nl: `Hoe laat gaat het open?`, ipa: `o KTOO-rey ot-FAR-te`},{pl: `Dzisiaj jest otwarte.`, nl: `Vandaag is het open.`, ipa: `DJEE-shay yest ot-FAR-te`},{pl: `Jutro jest zamknięte.`, nl: `Morgen is het gesloten.`, ipa: `YOO-tro yest zam-KNYEN-te`},{pl: `O dziesiątej.`, nl: `Om tien uur.`, ipa: `o dje-SHON-tey`},{pl: `Czy muzeum jest otwarte?`, nl: `Is het museum open?`, ipa: `tshi moo-ZE-oom yest ot-FAR-te`}], grammar: `Voor “om tien uur” zeg je “o dziesiątej”. Het woord “o” betekent hier “om”. Veel openingstijden worden in Polen in 24-uursnotatie geschreven, dus 17:00 is vijf uur ’s middags.`, practice: [`Zeg welke dag het vandaag is.`,`Vraag hoe laat iets open is.`,`Zeg dat iets morgen gesloten is.`,`Vraag of het museum open is.`,`Oefen “o dziesiątej” met andere getallen die je kent.`]},{day: 7, title: `Richtingen vragen`, title_native: `Pytanie o drogę`, focus: `In de oude stad van Krakau zoek je het station, een plein of je hotel. Je leert korte richtingszinnen begrijpen.`, vocab: [{pl: `dworzec`, nl: `station`, ipa: `DVO-zhets`},{pl: `hotel`, nl: `hotel`, ipa: `HO-tel`},{pl: `rynek`, nl: `marktplein`, ipa: `RI-nek`},{pl: `ulica`, nl: `straat`, ipa: `oo-LEE-tsa`},{pl: `prawo`, nl: `rechts`, ipa: `PRA-vo`},{pl: `lewo`, nl: `links`, ipa: `LE-vo`},{pl: `prosto`, nl: `rechtdoor`, ipa: `PRO-sto`},{pl: `blisko`, nl: `dichtbij`, ipa: `BLEES-ko`},{pl: `daleko`, nl: `ver`, ipa: `da-LE-ko`},{pl: `mapa`, nl: `kaart`, ipa: `MA-pa`}], phrases: [{pl: `Gdzie jest dworzec?`, nl: `Waar is het station?`, ipa: `gdje yest DVO-zhets`},{pl: `Gdzie jest mój hotel?`, nl: `Waar is mijn hotel?`, ipa: `gdje yest mooy HO-tel`},{pl: `Proszę iść prosto.`, nl: `Ga rechtdoor, alstublieft.`, ipa: `PRO-she eeshch PRO-sto`},{pl: `W prawo.`, nl: `Naar rechts.`, ipa: `v PRA-vo`},{pl: `W lewo.`, nl: `Naar links.`, ipa: `v LE-vo`},{pl: `Czy to daleko?`, nl: `Is het ver?`, ipa: `tshi to da-LE-ko`}], grammar: `“Gdzie jest...?” betekent “Waar is...?” en werkt met bijna elke plaatsnaam. Richtingen zijn kort en praktisch: “prosto”, “w prawo”, “w lewo”. Als je iets niet begrijpt, kun je “Jeszcze raz, proszę” zeggen: nog een keer, alstublieft.`, practice: [`Vraag waar het station is.`,`Vraag of iets ver is.`,`Geef drie richtingen: rechtdoor, rechts, links.`,`Vraag waar je hotel is.`,`Oefen met een kaart: wijs en zeg “tutaj” en “tam”.`]},{day: 8, title: `Openbaar vervoer`, title_native: `Transport publiczny`, focus: `In Warschau neem je tram, bus of metro. Je leert tickets kopen en vragen waar je moet uitstappen.`, vocab: [{pl: `bilet`, nl: `ticket`, ipa: `BEE-let`},{pl: `autobus`, nl: `bus`, ipa: `ow-TO-boos`},{pl: `tramwaj`, nl: `tram`, ipa: `TRAM-vay`},{pl: `metro`, nl: `metro`, ipa: `ME-tro`},{pl: `przystanek`, nl: `halte`, ipa: `pshi-STA-nek`},{pl: `stacja`, nl: `station`, ipa: `STA-tsja`},{pl: `kierunek`, nl: `richting`, ipa: `kye-ROO-nek`},{pl: `wysiadać`, nl: `uitstappen`, ipa: `vi-SHA-datsj`},{pl: `jechać`, nl: `rijden / gaan`, ipa: `YE-hatsj`},{pl: `kontrola`, nl: `controle`, ipa: `kon-TRO-la`}], phrases: [{pl: `Poproszę bilet.`, nl: `Ik wil graag een ticket.`, ipa: `po-PRO-she BEE-let`},{pl: `Gdzie jest przystanek?`, nl: `Waar is de halte?`, ipa: `gdje yest pshi-STA-nek`},{pl: `Czy ten tramwaj jedzie do centrum?`, nl: `Gaat deze tram naar het centrum?`, ipa: `tshi ten TRAM-vay YE-dje do TSEN-troom`},{pl: `Gdzie mam wysiąść?`, nl: `Waar moet ik uitstappen?`, ipa: `gdje mam VI-shonshch`},{pl: `Jadę do centrum.`, nl: `Ik ga naar het centrum.`, ipa: `YA-de do TSEN-troom`},{pl: `Czy to dobra stacja?`, nl: `Is dit het juiste station?`, ipa: `tshi to DO-bra STA-tsja`}], grammar: `“Do” betekent vaak “naar” bij bestemmingen: “do centrum”, “do hotelu”, “do muzeum”. In het Pools verandert het woord na “do” vaak, maar vaste combinaties helpen je onderweg enorm. “Ten” betekent “deze” bij mannelijke woorden zoals “tramwaj”.`, practice: [`Koop een ticket in het Pools.`,`Vraag of de tram naar het centrum gaat.`,`Vraag waar je moet uitstappen.`,`Zeg dat je naar het centrum gaat.`,`Zoek op een kaart een “przystanek” en zeg de naam hardop.`]},{day: 9, title: `Inchecken in een hotel`, title_native: `Meldowanie w hotelu`, focus: `In Zakopane kom je aan bij je hotel of pension. Je leert praten over reservering, paspoort, kamer en ontbijt.`, vocab: [{pl: `rezerwacja`, nl: `reservering`, ipa: `re-zer-VA-tsja`},{pl: `pokój`, nl: `kamer`, ipa: `PO-kooy`},{pl: `paszport`, nl: `paspoort`, ipa: `PASH-port`},{pl: `klucz`, nl: `sleutel`, ipa: `klootch`},{pl: `śniadanie`, nl: `ontbijt`, ipa: `shnya-DA-nye`},{pl: `winda`, nl: `lift`, ipa: `VEEN-da`},{pl: `łazienka`, nl: `badkamer`, ipa: `wa-ZHYEN-ka`},{pl: `łóżko`, nl: `bed`, ipa: `WOOSH-ko`},{pl: `noc`, nl: `nacht`, ipa: `nots`},{pl: `nazwisko`, nl: `achternaam`, ipa: `naz-VEES-ko`}], phrases: [{pl: `Mam rezerwację.`, nl: `Ik heb een reservering.`, ipa: `mam re-zer-VA-tsye`},{pl: `Na nazwisko Cannon.`, nl: `Op naam Cannon.`, ipa: `na naz-VEES-ko Cannon`},{pl: `Poproszę paszport.`, nl: `Uw paspoort, alstublieft.`, ipa: `po-PRO-she PASH-port`},{pl: `Gdzie jest pokój?`, nl: `Waar is de kamer?`, ipa: `gdje yest PO-kooy`},{pl: `Czy śniadanie jest w cenie?`, nl: `Is ontbijt inbegrepen?`, ipa: `tshi shnya-DA-nye yest v TSE-nye`},{pl: `Czy jest winda?`, nl: `Is er een lift?`, ipa: `tshi yest VEEN-da`}], grammar: `Bij een hotel gebruik je vaak “mam” voor “ik heb”: “Mam rezerwację”. Je kunt “na nazwisko...” gebruiken om te zeggen op welke naam iets staat. In Polen kan men bij het inchecken om een identiteitsbewijs vragen, vooral bij hotels.`, practice: [`Zeg dat je een reservering hebt.`,`Geef je achternaam met “na nazwisko”.`,`Vraag of ontbijt inbegrepen is.`,`Vraag waar je kamer is.`,`Vraag of er een lift is.`]},{day: 10, title: `Eten in een restaurant`, title_native: `Jedzenie w restauracji`, focus: `In Lublin ga je uit eten en wil je een tafel, menu en gerecht bestellen. Je leert praktische restauranttaal.`, vocab: [{pl: `restauracja`, nl: `restaurant`, ipa: `res-tow-RA-tsja`},{pl: `stolik`, nl: `tafel`, ipa: `STO-leek`},{pl: `menu`, nl: `menu`, ipa: `ME-noo`},{pl: `zupa`, nl: `soep`, ipa: `ZOO-pa`},{pl: `pierogi`, nl: `pierogi / gevulde deegkussentjes`, ipa: `pye-RO-gee`},{pl: `kurczak`, nl: `kip`, ipa: `KOOR-chak`},{pl: `ryba`, nl: `vis`, ipa: `RI-ba`},{pl: `sałatka`, nl: `salade`, ipa: `sa-WAT-ka`},{pl: `deser`, nl: `dessert`, ipa: `DE-ser`},{pl: `napój`, nl: `drankje`, ipa: `NA-pooy`}], phrases: [{pl: `Poproszę stolik dla dwóch osób.`, nl: `Een tafel voor twee personen, alstublieft.`, ipa: `po-PRO-she STO-leek dla dvooh O-soop`},{pl: `Czy mogę zobaczyć menu?`, nl: `Mag ik het menu zien?`, ipa: `tshi MO-ge zo-BA-chits ME-noo`},{pl: `Poproszę pierogi.`, nl: `Ik wil graag pierogi.`, ipa: `po-PRO-she pye-RO-gee`},{pl: `Co pan poleca?`, nl: `Wat raadt u aan?`, ipa: `tso pan po-LE-tsa`},{pl: `Co pani poleca?`, nl: `Wat raadt u aan?`, ipa: `tso PA-nee po-LE-tsa`},{pl: `To było bardzo dobre.`, nl: `Dat was erg lekker.`, ipa: `to BI-wo BAR-dzo DO-bre`}], grammar: `“Dla dwóch osób” betekent “voor twee personen”. Bij beleefd vragen aan een man gebruik je “pan”, aan een vrouw “pani”. “Co pan poleca?” en “Co pani poleca?” zijn zeer nuttige restaurantzinnen.`, practice: [`Vraag om een tafel voor twee personen.`,`Vraag om het menu.`,`Bestel pierogi.`,`Vraag een aanbeveling aan een man en aan een vrouw.`,`Zeg dat het erg lekker was.`]},{day: 11, title: `Dieetwensen en allergieën`, title_native: `Dieta i alergie`, focus: `In een restaurant in Toruń moet je aangeven wat je niet eet of waarvoor je allergisch bent. Vandaag leer je veilig en duidelijk communiceren.`, vocab: [{pl: `alergia`, nl: `allergie`, ipa: `a-LER-gja`},{pl: `orzechy`, nl: `noten`, ipa: `o-ZHE-hi`},{pl: `mleko`, nl: `melk`, ipa: `MLE-ko`},{pl: `gluten`, nl: `gluten`, ipa: `GLOO-ten`},{pl: `mięso`, nl: `vlees`, ipa: `MYEN-so`},{pl: `wegetariański`, nl: `vegetarisch`, ipa: `ve-ge-ta-RYAN-ski`},{pl: `wegański`, nl: `veganistisch`, ipa: `ve-GAN-ski`},{pl: `bez`, nl: `zonder`, ipa: `bez`},{pl: `ostry`, nl: `pittig`, ipa: `OS-tri`},{pl: `łagodny`, nl: `mild`, ipa: `wa-GOD-ni`}], phrases: [{pl: `Mam alergię na orzechy.`, nl: `Ik ben allergisch voor noten.`, ipa: `mam a-LER-gye na o-ZHE-hi`},{pl: `Bez mięsa, proszę.`, nl: `Zonder vlees, alstublieft.`, ipa: `bez MYEN-sa PRO-she`},{pl: `Czy to jest wegetariańskie?`, nl: `Is dit vegetarisch?`, ipa: `tshi to yest ve-ge-ta-RYAN-skye`},{pl: `Czy to jest wegańskie?`, nl: `Is dit veganistisch?`, ipa: `tshi to yest ve-GAN-skye`},{pl: `Czy to jest ostre?`, nl: `Is dit pittig?`, ipa: `tshi to yest OS-tre`},{pl: `Poproszę coś łagodnego.`, nl: `Ik wil graag iets milds.`, ipa: `po-PRO-she tsosh wa-GOD-ne-go`}], grammar: `“Bez” betekent “zonder” en is heel handig: “bez mięsa”, “bez mleka”, “bez glutenu”. Voor allergieën zeg je “Mam alergię na...”. Spreek langzaam en wijs eventueel naar geschreven woorden als het om gezondheid gaat.`, practice: [`Zeg dat je allergisch bent voor noten.`,`Vraag of een gerecht vegetarisch is.`,`Vraag of iets pittig is.`,`Bestel iets zonder vlees.`,`Maak een zin met “bez” plus een ingrediënt.`]},{day: 12, title: `Boodschappen doen`, title_native: `Zakupy spożywcze`, focus: `In een kleine winkel in Białystok koop je water, brood en fruit. Je leert producten herkennen en eenvoudige hoeveelheden vragen.`, vocab: [{pl: `sklep`, nl: `winkel`, ipa: `sklep`},{pl: `chleb`, nl: `brood`, ipa: `hlep`},{pl: `ser`, nl: `kaas`, ipa: `ser`},{pl: `jabłko`, nl: `appel`, ipa: `YAB-wko`},{pl: `banan`, nl: `banaan`, ipa: `BA-nan`},{pl: `woda gazowana`, nl: `bruiswater`, ipa: `VO-da ga-zo-VA-na`},{pl: `woda niegazowana`, nl: `plat water`, ipa: `VO-da nye-ga-zo-VA-na`},{pl: `torba`, nl: `tas`, ipa: `TOR-ba`},{pl: `kasa`, nl: `kassa`, ipa: `KA-sa`},{pl: `paragon`, nl: `bon`, ipa: `pa-RA-gon`}], phrases: [{pl: `Poproszę chleb.`, nl: `Ik wil graag brood.`, ipa: `po-PRO-she hlep`},{pl: `Poproszę dwa jabłka.`, nl: `Ik wil graag twee appels.`, ipa: `po-PRO-she dva YAB-wka`},{pl: `Czy jest woda niegazowana?`, nl: `Is er plat water?`, ipa: `tshi yest VO-da nye-ga-zo-VA-na`},{pl: `Czy potrzebuje pan torbę?`, nl: `Heeft u een tas nodig?`, ipa: `tshi po-tshe-BOO-ye pan TOR-be`},{pl: `Tak, poproszę.`, nl: `Ja, graag.`, ipa: `tak po-PRO-she`},{pl: `Nie, dziękuję.`, nl: `Nee, dank u.`, ipa: `nye djen-KOO-ye`}], grammar: `In winkels hoor je vaak “Czy potrzebuje pan/pani torbę?” voor “Heeft u een tas nodig?” Antwoorden kan simpel: “Tak, poproszę” of “Nie, dziękuję”. Poolse winkels gebruiken vaak korte, praktische gesprekken bij de kassa.`, practice: [`Bestel brood.`,`Vraag om twee appels.`,`Vraag naar plat water.`,`Antwoord ja op de vraag over een tas.`,`Antwoord nee en bedank beleefd.`]},{day: 13, title: `Kleding en souvenirs kopen`, title_native: `Kupowanie ubrań i pamiątek`, focus: `In een winkelstraat in Krakau koop je een souvenir of kledingstuk. Je leert vragen naar maat, kleur en prijs.`, vocab: [{pl: `pamiątka`, nl: `souvenir`, ipa: `pa-MYONT-ka`},{pl: `koszulka`, nl: `T-shirt`, ipa: `ko-SHOOL-ka`},{pl: `czapka`, nl: `pet / muts`, ipa: `CHAP-ka`},{pl: `rozmiar`, nl: `maat`, ipa: `ROZ-myar`},{pl: `kolor`, nl: `kleur`, ipa: `KO-lor`},{pl: `biały`, nl: `wit`, ipa: `BIA-wi`},{pl: `czarny`, nl: `zwart`, ipa: `CHAR-ni`},{pl: `czerwony`, nl: `rood`, ipa: `cher-VO-ni`},{pl: `niebieski`, nl: `blauw`, ipa: `nye-BYES-ki`},{pl: `drogi`, nl: `duur`, ipa: `DRO-gee`}], phrases: [{pl: `Ile kosztuje ta pamiątka?`, nl: `Hoeveel kost dit souvenir?`, ipa: `EE-le kosh-TOO-ye ta pa-MYONT-ka`},{pl: `Czy macie większy rozmiar?`, nl: `Heeft u een grotere maat?`, ipa: `tshi MA-chye VYENK-shi ROZ-myar`},{pl: `Czy macie mniejszy rozmiar?`, nl: `Heeft u een kleinere maat?`, ipa: `tshi MA-chye MNYEY-shi ROZ-myar`},{pl: `Poproszę tę koszulkę.`, nl: `Ik wil graag dit T-shirt.`, ipa: `po-PRO-she ten ko-SHOOL-ke`},{pl: `To jest za drogie.`, nl: `Dat is te duur.`, ipa: `to yest za DRO-gye`},{pl: `Czy mogę przymierzyć?`, nl: `Mag ik het passen?`, ipa: `tshi MO-ge pshi-MYE-zhits`}], grammar: `“Ta” betekent “deze” bij vrouwelijke woorden zoals “pamiątka”, en “ten” bij mannelijke woorden. In de praktijk kun je ook wijzen en “to” gebruiken: “Ile kosztuje to?” Dat is eenvoudig en wordt meestal begrepen.`, practice: [`Vraag hoeveel een souvenir kost.`,`Vraag om een grotere maat.`,`Vraag of je iets mag passen.`,`Zeg dat iets te duur is.`,`Noem drie kleuren in het Pools.`]},{day: 14, title: `Taxi en ritdiensten`, title_native: `Taksówka i przejazdy`, focus: `In Katowice neem je een taxi of app-rit naar je hotel. Je leert adressen geven, de prijs vragen en bevestigen waar je heen wilt.`, vocab: [{pl: `taksówka`, nl: `taxi`, ipa: `tak-SOOF-ka`},{pl: `adres`, nl: `adres`, ipa: `A-dres`},{pl: `lotnisko`, nl: `luchthaven`, ipa: `lot-NEES-ko`},{pl: `centrum`, nl: `centrum`, ipa: `TSEN-troom`},{pl: `hotel`, nl: `hotel`, ipa: `HO-tel`},{pl: `proszę jechać`, nl: `rijdt u alstublieft`, ipa: `PRO-she YE-hatsj`},{pl: `szybko`, nl: `snel`, ipa: `SHIP-ko`},{pl: `wolno`, nl: `langzaam`, ipa: `VOL-no`},{pl: `tutaj`, nl: `hier`, ipa: `TOO-tay`},{pl: `gotówka`, nl: `contant geld`, ipa: `go-TOOF-ka`}], phrases: [{pl: `Proszę jechać do hotelu.`, nl: `Rijdt u naar het hotel, alstublieft.`, ipa: `PRO-she YE-hatsj do ho-TE-loo`},{pl: `To jest adres.`, nl: `Dit is het adres.`, ipa: `to yest A-dres`},{pl: `Ile będzie kosztować?`, nl: `Hoeveel zal het kosten?`, ipa: `EE-le BEN-dje kosh-TO-vatsj`},{pl: `Proszę zatrzymać się tutaj.`, nl: `Stop hier, alstublieft.`, ipa: `PRO-she za-tshi-MATS shen TOO-tay`},{pl: `Czy mogę zapłacić kartą?`, nl: `Kan ik met kaart betalen?`, ipa: `tshi MO-ge za-PWA-chits KAR-tom`},{pl: `Mam tylko gotówkę.`, nl: `Ik heb alleen contant geld.`, ipa: `mam TIL-ko go-TOOF-ke`}], grammar: `Na “do” verandert “hotel” in “hotelu”: “do hotelu”. Voor reizigers is het genoeg om deze vaste vorm te kennen. Toon bij twijfel het adres op je telefoon en zeg: “To jest adres.”`, practice: [`Vraag een chauffeur naar je hotel te rijden.`,`Vraag hoeveel de rit zal kosten.`,`Zeg dat dit het adres is.`,`Vraag of je met kaart kunt betalen.`,`Vraag de chauffeur hier te stoppen.`]},{day: 15, title: `Problemen en hulp vragen`, title_native: `Problemy i prośba o pomoc`, focus: `In een druk station in Wrocław raak je iets kwijt of heb je hulp nodig. Vandaag leer je duidelijke noodzinnen zonder paniek.`, vocab: [{pl: `pomoc`, nl: `hulp`, ipa: `PO-mots`},{pl: `problem`, nl: `probleem`, ipa: `PRO-blem`},{pl: `zgubiłem`, nl: `ik ben kwijtgeraakt, man spreekt`, ipa: `zgoo-BEE-wem`},{pl: `zgubiłam`, nl: `ik ben kwijtgeraakt, vrouw spreekt`, ipa: `zgoo-BEE-wam`},{pl: `telefon`, nl: `telefoon`, ipa: `te-LE-fon`},{pl: `portfel`, nl: `portemonnee`, ipa: `PORT-fel`},{pl: `paszport`, nl: `paspoort`, ipa: `PASH-port`},{pl: `policja`, nl: `politie`, ipa: `po-LEETS-ja`},{pl: `apteka`, nl: `apotheek`, ipa: `ap-TE-ka`},{pl: `szpital`, nl: `ziekenhuis`, ipa: `SHPEE-tal`}], phrases: [{pl: `Potrzebuję pomocy.`, nl: `Ik heb hulp nodig.`, ipa: `po-tshe-BOO-ye PO-mo-tsi`},{pl: `Mam problem.`, nl: `Ik heb een probleem.`, ipa: `mam PRO-blem`},{pl: `Zgubiłem telefon.`, nl: `Ik ben mijn telefoon kwijt.`, ipa: `zgoo-BEE-wem te-LE-fon`},{pl: `Zgubiłam portfel.`, nl: `Ik ben mijn portemonnee kwijt.`, ipa: `zgoo-BEE-wam PORT-fel`},{pl: `Gdzie jest policja?`, nl: `Waar is de politie?`, ipa: `gdje yest po-LEETS-ja`},{pl: `Czy może mi pan pomóc?`, nl: `Kunt u mij helpen?`, ipa: `tshi MO-zhe mee pan PO-moots`}], grammar: `In het Pools verandert de verleden tijd soms afhankelijk van wie spreekt. Een man zegt “zgubiłem”, een vrouw zegt “zgubiłam”. In noodsituaties is duidelijkheid belangrijker dan perfecte grammatica.`, practice: [`Zeg dat je hulp nodig hebt.`,`Zeg dat je een probleem hebt.`,`Kies “zgubiłem” of “zgubiłam” voor jezelf.`,`Vraag waar de politie is.`,`Vraag beleefd of iemand je kan helpen.`]},{day: 16, title: `Bij de apotheek`, title_native: `W aptece`, focus: `In Poznań voel je je niet goed en ga je naar een apotheek. Je leert klachten benoemen en om eenvoudige middelen vragen.`, vocab: [{pl: `apteka`, nl: `apotheek`, ipa: `ap-TE-ka`},{pl: `ból`, nl: `pijn`, ipa: `bool`},{pl: `głowa`, nl: `hoofd`, ipa: `GWO-va`},{pl: `brzuch`, nl: `buik`, ipa: `bzhuh`},{pl: `gardło`, nl: `keel`, ipa: `GAR-dwo`},{pl: `gorączka`, nl: `koorts`, ipa: `go-RONCH-ka`},{pl: `kaszel`, nl: `hoest`, ipa: `KA-shel`},{pl: `lekarstwo`, nl: `medicijn`, ipa: `le-KAR-stvo`},{pl: `tabletka`, nl: `tablet`, ipa: `ta-BLET-ka`},{pl: `recepta`, nl: `recept`, ipa: `re-TSEP-ta`}], phrases: [{pl: `Boli mnie głowa.`, nl: `Ik heb hoofdpijn.`, ipa: `BO-lee mnye GWO-va`},{pl: `Boli mnie brzuch.`, nl: `Ik heb buikpijn.`, ipa: `BO-lee mnye bzhuh`},{pl: `Mam gorączkę.`, nl: `Ik heb koorts.`, ipa: `mam go-RONCH-ke`},{pl: `Mam kaszel.`, nl: `Ik heb hoest.`, ipa: `mam KA-shel`},{pl: `Czy potrzebuję recepty?`, nl: `Heb ik een recept nodig?`, ipa: `tshi po-tshe-BOO-ye re-TSEP-ti`},{pl: `Poproszę coś na ból gardła.`, nl: `Ik wil graag iets tegen keelpijn.`, ipa: `po-PRO-she tsosh na bool GAR-dwa`}], grammar: `Voor pijn gebruik je vaak “Boli mnie...” plus het lichaamsdeel. Letterlijk betekent het “het doet mij pijn”. “Coś na...” betekent “iets tegen/voor”, bijvoorbeeld “coś na ból głowy”.`, practice: [`Zeg dat je hoofdpijn hebt.`,`Zeg dat je koorts hebt.`,`Vraag iets tegen keelpijn.`,`Vraag of je een recept nodig hebt.`,`Maak een zin met “Boli mnie...”.`]},{day: 17, title: `Mensen beschrijven`, title_native: `Opisywanie ludzi`, focus: `In een hostel in Gdańsk praat je over vrienden, personeel of reisgenoten. Je leert eenvoudige beschrijvingen gebruiken.`, vocab: [{pl: `miły`, nl: `aardig`, ipa: `MEE-wi`},{pl: `miła`, nl: `aardig, vrouwelijk`, ipa: `MEE-wa`},{pl: `wysoki`, nl: `lang`, ipa: `vi-SO-ki`},{pl: `niski`, nl: `kort / klein`, ipa: `NEES-ki`},{pl: `młody`, nl: `jong`, ipa: `MWO-di`},{pl: `starszy`, nl: `ouder`, ipa: `STAR-shi`},{pl: `przyjaciel`, nl: `vriend`, ipa: `pshi-YA-chyel`},{pl: `przyjaciółka`, nl: `vriendin`, ipa: `pshi-ya-CHOOW-ka`},{pl: `rodzina`, nl: `familie`, ipa: `ro-DJEE-na`},{pl: `dziecko`, nl: `kind`, ipa: `DJET-sko`}], phrases: [{pl: `On jest miły.`, nl: `Hij is aardig.`, ipa: `on yest MEE-wi`},{pl: `Ona jest miła.`, nl: `Zij is aardig.`, ipa: `O-na yest MEE-wa`},{pl: `To jest mój przyjaciel.`, nl: `Dit is mijn vriend.`, ipa: `to yest mooy pshi-YA-chyel`},{pl: `To jest moja przyjaciółka.`, nl: `Dit is mijn vriendin.`, ipa: `to yest MO-ya pshi-ya-CHOOW-ka`},{pl: `Jestem z rodziną.`, nl: `Ik ben met familie.`, ipa: `YES-tem z ro-DJEE-nom`},{pl: `Czy to pana dziecko?`, nl: `Is dat uw kind?`, ipa: `tshi to PA-na DJET-sko`}], grammar: `Bij bijvoeglijke naamwoorden zie je vaak mannelijke en vrouwelijke vormen: “miły” voor een man, “miła” voor een vrouw. Ook “mój” en “moja” veranderen: “mój przyjaciel”, maar “moja przyjaciółka”.`, practice: [`Beschrijf een man als aardig.`,`Beschrijf een vrouw als aardig.`,`Stel een vriend voor.`,`Zeg dat je met familie bent.`,`Maak twee zinnen met “mój” en “moja”.`]},{day: 18, title: `Weer en kleding`, title_native: `Pogoda i ubrania`, focus: `In Zakopane verandert het weer snel. Je leert praten over regen, kou, zon en wat je nodig hebt.`, vocab: [{pl: `pogoda`, nl: `weer`, ipa: `po-GO-da`},{pl: `słońce`, nl: `zon`, ipa: `SWON-tse`},{pl: `deszcz`, nl: `regen`, ipa: `deshch`},{pl: `śnieg`, nl: `sneeuw`, ipa: `shnyek`},{pl: `zimno`, nl: `koud`, ipa: `ZHEEM-no`},{pl: `ciepło`, nl: `warm`, ipa: `CHEP-wo`},{pl: `wiatr`, nl: `wind`, ipa: `vyatr`},{pl: `kurtka`, nl: `jas`, ipa: `KOORT-ka`},{pl: `parasol`, nl: `paraplu`, ipa: `pa-RA-sol`},{pl: `buty`, nl: `schoenen`, ipa: `BOO-ti`}], phrases: [{pl: `Jaka jest pogoda?`, nl: `Hoe is het weer?`, ipa: `YA-ka yest po-GO-da`},{pl: `Jest zimno.`, nl: `Het is koud.`, ipa: `yest ZHEEM-no`},{pl: `Jest ciepło.`, nl: `Het is warm.`, ipa: `yest CHEP-wo`},{pl: `Pada deszcz.`, nl: `Het regent.`, ipa: `PA-da deshch`},{pl: `Pada śnieg.`, nl: `Het sneeuwt.`, ipa: `PA-da shnyek`},{pl: `Potrzebuję parasola.`, nl: `Ik heb een paraplu nodig.`, ipa: `po-tshe-BOO-ye pa-ra-SO-la`}], grammar: `Voor weer gebruik je vaak onpersoonlijke zinnen: “Jest zimno” betekent letterlijk “het is koud”. “Pada deszcz” betekent letterlijk “regen valt”. Deze vaste zinnen klinken natuurlijk en zijn makkelijk te gebruiken.`, practice: [`Vraag hoe het weer is.`,`Zeg dat het regent.`,`Zeg dat het koud is.`,`Zeg dat je een paraplu nodig hebt.`,`Beschrijf het weer vandaag in twee Poolse zinnen.`]},{day: 19, title: `Dagelijkse routines`, title_native: `Codzienne czynności`, focus: `Tijdens een langer verblijf in Warschau praat je over wat je vandaag doet. Je leert eenvoudige werkwoorden voor dagelijkse plannen.`, vocab: [{pl: `jeść`, nl: `eten`, ipa: `yeshch`},{pl: `pić`, nl: `drinken`, ipa: `peech`},{pl: `spać`, nl: `slapen`, ipa: `spatsj`},{pl: `iść`, nl: `gaan te voet`, ipa: `eeshch`},{pl: `robić`, nl: `doen / maken`, ipa: `RO-beech`},{pl: `kupować`, nl: `kopen`, ipa: `koo-PO-vatsj`},{pl: `czekać`, nl: `wachten`, ipa: `CHE-katsj`},{pl: `szukać`, nl: `zoeken`, ipa: `SHOO-katsj`},{pl: `dzisiaj`, nl: `vandaag`, ipa: `DJEE-shay`},{pl: `potem`, nl: `daarna`, ipa: `PO-tem`}], phrases: [{pl: `Idę do sklepu.`, nl: `Ik ga naar de winkel.`, ipa: `EE-de do SKLE-poo`},{pl: `Jem śniadanie.`, nl: `Ik eet ontbijt.`, ipa: `yem shnya-DA-nye`},{pl: `Piję kawę.`, nl: `Ik drink koffie.`, ipa: `PEE-ye KA-ve`},{pl: `Czekam na autobus.`, nl: `Ik wacht op de bus.`, ipa: `CHE-kam na ow-TO-boos`},{pl: `Szukam hotelu.`, nl: `Ik zoek het hotel.`, ipa: `SHOO-kam ho-TE-loo`},{pl: `Co robisz dzisiaj?`, nl: `Wat doe je vandaag?`, ipa: `tso RO-beesh DJEE-shay`}], grammar: `Veel werkwoorden krijgen in de ik-vorm een uitgang zoals “-ę” of “-am”: “idę”, “piję”, “czekam”, “szukam”. Leer ze als vaste reiszinnen. “Idę do...” is handig voor plaatsen waar je naartoe loopt.`, practice: [`Zeg dat je naar de winkel gaat.`,`Zeg dat je koffie drinkt.`,`Vraag wat iemand vandaag doet.`,`Zeg dat je op de bus wacht.`,`Zeg dat je het hotel zoekt.`]},{day: 20, title: `Uitnodigingen en sociale plannen`, title_native: `Zaproszenia i plany towarzyskie`, focus: `In Krakau ontmoet je locals of andere reizigers en wil je iets afspreken. Je leert eenvoudige uitnodigingen en reacties.`, vocab: [{pl: `spotkanie`, nl: `ontmoeting / afspraak`, ipa: `spot-KA-nye`},{pl: `kawiarnia`, nl: `café`, ipa: `ka-vyar-NYA`},{pl: `bar`, nl: `bar`, ipa: `bar`},{pl: `wieczór`, nl: `avond`, ipa: `VYE-tsjoor`},{pl: `rano`, nl: `ochtend`, ipa: `RA-no`},{pl: `teraz`, nl: `nu`, ipa: `TE-ras`},{pl: `później`, nl: `later`, ipa: `POOZH-nyey`},{pl: `razem`, nl: `samen`, ipa: `RA-zem`},{pl: `chętnie`, nl: `graag`, ipa: `HEN-tnye`},{pl: `niestety`, nl: `helaas`, ipa: `nye-STE-ti`}], phrases: [{pl: `Czy chcesz iść na kawę?`, nl: `Wil je koffie gaan drinken?`, ipa: `tshi htshesh eeshch na KA-ve`},{pl: `Chętnie.`, nl: `Graag.`, ipa: `HEN-tnye`},{pl: `Niestety, nie mogę.`, nl: `Helaas, ik kan niet.`, ipa: `nye-STE-ti nye MO-ge`},{pl: `Może później?`, nl: `Misschien later?`, ipa: `MO-zhe POOZH-nyey`},{pl: `Idziemy razem?`, nl: `Gaan we samen?`, ipa: `ee-DJYE-mi RA-zem`},{pl: `Do zobaczenia wieczorem.`, nl: `Tot vanavond.`, ipa: `do zo-ba-CHEN-ya vye-CHO-rem`}], grammar: `“Czy chcesz...?” betekent “wil je...?” en is informeel. Gebruik dit met mensen die je net sociaal hebt ontmoet. Voor beleefder of formeler spreken kun je beter eenvoudig blijven met “Może kawa?”: misschien koffie?`, practice: [`Nodig iemand uit voor koffie.`,`Reageer met “Chętnie”.`,`Zeg dat je helaas niet kunt.`,`Stel “misschien later?” voor.`,`Zeg “tot vanavond”.`]},{day: 21, title: `Telefoneren en berichten`, title_native: `Telefon i wiadomości`, focus: `Tijdens je reis moet je soms bellen, appen of een reservering bevestigen. Vandaag leer je basiszinnen voor telefoon en berichten.`, vocab: [{pl: `telefon`, nl: `telefoon`, ipa: `te-LE-fon`},{pl: `wiadomość`, nl: `bericht`, ipa: `vya-DO-moshch`},{pl: `numer`, nl: `nummer`, ipa: `NOO-mer`},{pl: `dzwonić`, nl: `bellen`, ipa: `DZVO-neech`},{pl: `pisać`, nl: `schrijven / appen`, ipa: `PEE-satsj`},{pl: `internet`, nl: `internet`, ipa: `IN-ter-net`},{pl: `hasło`, nl: `wachtwoord`, ipa: `HA-swo`},{pl: `ładowarka`, nl: `oplader`, ipa: `wa-do-VAR-ka`},{pl: `bateria`, nl: `batterij`, ipa: `ba-TE-rja`},{pl: `kontakt`, nl: `contact`, ipa: `KON-takt`}], phrases: [{pl: `Jaki jest numer telefonu?`, nl: `Wat is het telefoonnummer?`, ipa: `YA-ki yest NOO-mer te-le-FO-noo`},{pl: `Czy mogę zadzwonić?`, nl: `Mag ik bellen?`, ipa: `tshi MO-ge za-DZVO-neech`},{pl: `Napiszę wiadomość.`, nl: `Ik stuur een bericht.`, ipa: `na-PEE-she vya-DO-moshch`},{pl: `Czy jest Wi-Fi?`, nl: `Is er wifi?`, ipa: `tshi yest VEE-fee`},{pl: `Jakie jest hasło?`, nl: `Wat is het wachtwoord?`, ipa: `YA-kye yest HA-swo`},{pl: `Potrzebuję ładowarki.`, nl: `Ik heb een oplader nodig.`, ipa: `po-tshe-BOO-ye wa-do-VAR-ki`}], grammar: `“Czy mogę...?” betekent “mag ik / kan ik...?” en werkt in veel situaties: “Czy mogę zadzwonić?”, “Czy mogę zapłacić kartą?”, “Czy mogę zobaczyć menu?” Dit is een van de meest nuttige structuren voor reizigers.`, practice: [`Vraag naar het telefoonnummer.`,`Vraag of je mag bellen.`,`Vraag of er wifi is.`,`Vraag naar het wachtwoord.`,`Zeg dat je een oplader nodig hebt.`]},{day: 22, title: `Meningen en voorkeuren`, title_native: `Opinie i preferencje`, focus: `In een café in Lublin praat je over wat je leuk vindt, wat lekker is en wat je liever wilt. Je leert eenvoudige meningen geven.`, vocab: [{pl: `lubię`, nl: `ik vind leuk`, ipa: `LOO-bye`},{pl: `nie lubię`, nl: `ik vind niet leuk`, ipa: `nye LOO-bye`},{pl: `wolę`, nl: `ik heb liever`, ipa: `VO-le`},{pl: `dobry`, nl: `goed / lekker`, ipa: `DO-bri`},{pl: `zły`, nl: `slecht`, ipa: `zwi`},{pl: `piękny`, nl: `mooi`, ipa: `PYENK-ni`},{pl: `ładny`, nl: `mooi / leuk`, ipa: `WAD-ni`},{pl: `smaczny`, nl: `lekker`, ipa: `SMACH-ni`},{pl: `ciekawy`, nl: `interessant`, ipa: `che-KA-vi`},{pl: `nudny`, nl: `saai`, ipa: `NOOD-ni`}], phrases: [{pl: `Lubię polską kuchnię.`, nl: `Ik hou van de Poolse keuken.`, ipa: `LOO-bye POL-skom KOOH-nye`},{pl: `Nie lubię ostrego jedzenia.`, nl: `Ik hou niet van pittig eten.`, ipa: `nye LOO-bye OS-tre-go ye-DZEN-ya`},{pl: `Wolę kawę.`, nl: `Ik heb liever koffie.`, ipa: `VO-le KA-ve`},{pl: `To jest bardzo smaczne.`, nl: `Dit is erg lekker.`, ipa: `to yest BAR-dzo SMACH-ne`},{pl: `To miasto jest piękne.`, nl: `Deze stad is mooi.`, ipa: `to MYAS-to yest PYENK-ne`},{pl: `To jest ciekawe.`, nl: `Dat is interessant.`, ipa: `to yest che-KA-ve`}], grammar: `“Lubię” wordt gevolgd door wat je leuk vindt: “Lubię kawę”, “Lubię Kraków”. “Wolę” betekent “ik heb liever” en is handig bij keuzes. Bij eten hoor je vaak “smaczne”, het neutrale woord voor lekker.`, practice: [`Zeg dat je de Poolse keuken lekker vindt.`,`Zeg dat je niet van pittig eten houdt.`,`Zeg dat je liever koffie hebt.`,`Beschrijf een stad als mooi.`,`Geef één mening over een gerecht.`]},{day: 23, title: `Culturele bezoeken`, title_native: `Zwiedzanie i kultura`, focus: `Je bezoekt een museum, kerk of kasteel in Malbork of Krakau. Je leert vragen naar tickets, rondleidingen en foto’s.`, vocab: [{pl: `muzeum`, nl: `museum`, ipa: `moo-ZE-oom`},{pl: `zamek`, nl: `kasteel`, ipa: `ZA-mek`},{pl: `kościół`, nl: `kerk`, ipa: `KOSH-choow`},{pl: `bilet ulgowy`, nl: `kortingsticket`, ipa: `BEE-let ool-GO-vi`},{pl: `bilet normalny`, nl: `normaal ticket`, ipa: `BEE-let nor-MAL-ni`},{pl: `przewodnik`, nl: `gids`, ipa: `pshe-VOD-neek`},{pl: `wycieczka`, nl: `rondleiding / excursie`, ipa: `vi-CHESH-ka`},{pl: `zdjęcie`, nl: `foto`, ipa: `ZDYEHN-chye`},{pl: `wejście`, nl: `ingang`, ipa: `VEY-shchye`},{pl: `wyjście`, nl: `uitgang`, ipa: `VIY-shchye`}], phrases: [{pl: `Poproszę bilet normalny.`, nl: `Ik wil graag een normaal ticket.`, ipa: `po-PRO-she BEE-let nor-MAL-ni`},{pl: `Czy jest wycieczka po angielsku?`, nl: `Is er een rondleiding in het Engels?`, ipa: `tshi yest vi-CHESH-ka po an-GYEL-skoo`},{pl: `Czy mogę robić zdjęcia?`, nl: `Mag ik foto’s maken?`, ipa: `tshi MO-ge RO-beech ZDYEHN-cha`},{pl: `Gdzie jest wejście?`, nl: `Waar is de ingang?`, ipa: `gdje yest VEY-shchye`},{pl: `Gdzie jest wyjście?`, nl: `Waar is de uitgang?`, ipa: `gdje yest VIY-shchye`},{pl: `O której zaczyna się wycieczka?`, nl: `Hoe laat begint de rondleiding?`, ipa: `o KTOO-rey za-CHI-na shen vi-CHESH-ka`}], grammar: `Voor talen gebruik je “po” plus de taal: “po angielsku” is in het Engels, “po polsku” is in het Pools. Als Nederlandse spreker kun je ook vragen: “Czy mówi pan po angielsku?” als je hulp nodig hebt.`, practice: [`Koop een normaal ticket.`,`Vraag naar een rondleiding in het Engels.`,`Vraag of je foto’s mag maken.`,`Vraag waar de ingang is.`,`Vraag hoe laat de rondleiding begint.`]},{day: 24, title: `Treinreizen tussen steden`, title_native: `Podróż pociągiem między miastami`, focus: `Je reist van Warschau naar Krakau of van Gdańsk naar Poznań. Je leert stationstaal, perron, vertrektijd en vertraging.`, vocab: [{pl: `pociąg`, nl: `trein`, ipa: `PO-chong`},{pl: `peron`, nl: `perron`, ipa: `PE-ron`},{pl: `tor`, nl: `spoor`, ipa: `tor`},{pl: `odjazd`, nl: `vertrek`, ipa: `OD-yazd`},{pl: `przyjazd`, nl: `aankomst`, ipa: `PSHI-yazd`},{pl: `opóźnienie`, nl: `vertraging`, ipa: `o-poozh-NYE-nye`},{pl: `wagon`, nl: `wagon`, ipa: `VA-gon`},{pl: `miejsce`, nl: `plaats / stoel`, ipa: `MYES-tse`},{pl: `bagaż`, nl: `bagage`, ipa: `BA-gash`},{pl: `konduktor`, nl: `conducteur`, ipa: `kon-DOOK-tor`}], phrases: [{pl: `Gdzie jest peron trzeci?`, nl: `Waar is perron drie?`, ipa: `gdje yest PE-ron TSHE-chee`},{pl: `O której odjeżdża pociąg?`, nl: `Hoe laat vertrekt de trein?`, ipa: `o KTOO-rey od-YEZH-dzha PO-chong`},{pl: `Czy pociąg jest opóźniony?`, nl: `Is de trein vertraagd?`, ipa: `tshi PO-chong yest o-POOZH-nyo-ni`},{pl: `Mam miejsce numer pięć.`, nl: `Ik heb stoel nummer vijf.`, ipa: `mam MYES-tse NOO-mer pyentsj`},{pl: `To mój bagaż.`, nl: `Dat is mijn bagage.`, ipa: `to mooy BA-gash`},{pl: `Czy to pociąg do Krakowa?`, nl: `Is dit de trein naar Krakau?`, ipa: `tshi to PO-chong do kra-KO-va`}], grammar: `Plaatsnamen veranderen na “do”: “Kraków” wordt “do Krakowa”, “Warszawa” wordt “do Warszawy”. Dit zie je vaak op stations en tickets. Leer de vorm voor de steden die je echt gaat bezoeken.`, practice: [`Vraag waar perron drie is.`,`Vraag hoe laat de trein vertrekt.`,`Vraag of de trein vertraagd is.`,`Zeg je stoelnummer.`,`Vraag of dit de trein naar Krakau is.`]},{day: 25, title: `Accommodatieproblemen`, title_native: `Problemy z noclegiem`, focus: `In je appartement of hotelkamer in Wrocław werkt iets niet. Je leert problemen met kamer, wifi, water en geluid melden.`, vocab: [{pl: `pokój`, nl: `kamer`, ipa: `PO-kooy`},{pl: `klimatyzacja`, nl: `airconditioning`, ipa: `klee-ma-ti-ZA-tsja`},{pl: `ogrzewanie`, nl: `verwarming`, ipa: `o-gzhe-VA-nye`},{pl: `internet`, nl: `internet`, ipa: `IN-ter-net`},{pl: `prysznic`, nl: `douche`, ipa: `PRI-shnits`},{pl: `woda`, nl: `water`, ipa: `VO-da`},{pl: `hałas`, nl: `lawaai`, ipa: `HA-was`},{pl: `brudny`, nl: `vies`, ipa: `BROOD-ni`},{pl: `czysty`, nl: `schoon`, ipa: `CHI-sti`},{pl: `działać`, nl: `werken / functioneren`, ipa: `DJA-watsj`}], phrases: [{pl: `Internet nie działa.`, nl: `Het internet werkt niet.`, ipa: `IN-ter-net nye DJA-wa`},{pl: `Klimatyzacja nie działa.`, nl: `De airco werkt niet.`, ipa: `klee-ma-ti-ZA-tsja nye DJA-wa`},{pl: `W pokoju jest hałas.`, nl: `Er is lawaai in de kamer.`, ipa: `v po-KO-yoo yest HA-was`},{pl: `Prysznic jest zepsuty.`, nl: `De douche is kapot.`, ipa: `PRI-shnits yest zep-SOO-ti`},{pl: `Pokój jest brudny.`, nl: `De kamer is vies.`, ipa: `PO-kooy yest BROOD-ni`},{pl: `Czy mogę zmienić pokój?`, nl: `Kan ik van kamer veranderen?`, ipa: `tshi MO-ge ZMYE-nits PO-kooy`}], grammar: `“Nie działa” betekent “werkt niet” en is heel handig voor apparaten, internet, airco en verwarming. “Zepsuty” betekent kapot. Houd je klacht kort en duidelijk; dat werkt het beste bij recepties.`, practice: [`Zeg dat het internet niet werkt.`,`Zeg dat de douche kapot is.`,`Meld lawaai in de kamer.`,`Vraag of je van kamer kunt veranderen.`,`Beschrijf of iets schoon of vies is.`]},{day: 26, title: `Geld, bank en betalen`, title_native: `Pieniądze, bank i płatności`, focus: `In Warschau zoek je een geldautomaat of wil je betaalproblemen oplossen. Je leert woorden voor contant geld, kaart en wisselen.`, vocab: [{pl: `pieniądze`, nl: `geld`, ipa: `pye-NYON-dze`},{pl: `bank`, nl: `bank`, ipa: `bank`},{pl: `bankomat`, nl: `geldautomaat`, ipa: `ban-KO-mat`},{pl: `karta`, nl: `kaart`, ipa: `KAR-ta`},{pl: `gotówka`, nl: `contant geld`, ipa: `go-TOOF-ka`},{pl: `płatność`, nl: `betaling`, ipa: `PWAT-noshch`},{pl: `paragon`, nl: `bon`, ipa: `pa-RA-gon`},{pl: `reszta`, nl: `wisselgeld`, ipa: `RESH-ta`},{pl: `wymiana`, nl: `wisselen`, ipa: `vi-MYA-na`},{pl: `kurs`, nl: `wisselkoers`, ipa: `koers`}], phrases: [{pl: `Gdzie jest bankomat?`, nl: `Waar is een geldautomaat?`, ipa: `gdje yest ban-KO-mat`},{pl: `Czy mogę zapłacić kartą?`, nl: `Kan ik met kaart betalen?`, ipa: `tshi MO-ge za-PWA-chits KAR-tom`},{pl: `Czy mogę zapłacić gotówką?`, nl: `Kan ik contant betalen?`, ipa: `tshi MO-ge za-PWA-chits go-TOOF-kom`},{pl: `Poproszę paragon.`, nl: `De bon, alstublieft.`, ipa: `po-PRO-she pa-RA-gon`},{pl: `Nie mam gotówki.`, nl: `Ik heb geen contant geld.`, ipa: `nye mam go-TOOF-ki`},{pl: `Czy to dobra reszta?`, nl: `Klopt het wisselgeld?`, ipa: `tshi to DO-bra RESH-ta`}], grammar: `Voor betalen gebruik je “zapłacić” met “kartą” of “gotówką”. De uitgang “-ą” klinkt als een nasale “om”. Deze vormen komen vaak voor in dagelijkse gesprekken en zijn handig om letterlijk te onthouden.`, practice: [`Vraag waar een geldautomaat is.`,`Vraag of je met kaart kunt betalen.`,`Vraag of je contant kunt betalen.`,`Vraag om de bon.`,`Zeg dat je geen contant geld hebt.`]},{day: 27, title: `Lokale etiquette en beleefdheid`, title_native: `Lokalna etykieta i uprzejmość`, focus: `Je leert natuurlijke beleefdheid in Poolse situaties: begroeten bij binnenkomst, bedanken, iemand aanspreken en sorry zeggen. Dit helpt je in winkels, treinen en restaurants.`, vocab: [{pl: `uprzejmie`, nl: `beleefd`, ipa: `oo-PSHEY-mye`},{pl: `przepraszam`, nl: `sorry / pardon`, ipa: `pshe-PRA-sham`},{pl: `dziękuję`, nl: `dank u`, ipa: `djen-KOO-ye`},{pl: `proszę`, nl: `alstublieft`, ipa: `PRO-she`},{pl: `pan`, nl: `meneer / u`, ipa: `pan`},{pl: `pani`, nl: `mevrouw / u`, ipa: `PA-nee`},{pl: `państwo`, nl: `dames en heren / u meervoud`, ipa: `PAN-stvo`},{pl: `kolejka`, nl: `rij`, ipa: `ko-LEY-ka`},{pl: `miejsce`, nl: `plaats`, ipa: `MYES-tse`},{pl: `wolne`, nl: `vrij`, ipa: `VOL-ne`}], phrases: [{pl: `Przepraszam, czy to wolne?`, nl: `Pardon, is dit vrij?`, ipa: `pshe-PRA-sham tshi to VOL-ne`},{pl: `Czy tu jest kolejka?`, nl: `Is hier de rij?`, ipa: `tshi too yest ko-LEY-ka`},{pl: `Dziękuję za pomoc.`, nl: `Bedankt voor de hulp.`, ipa: `djen-KOO-ye za PO-mots`},{pl: `Bardzo mi miło.`, nl: `Heel aangenaam.`, ipa: `BAR-dzo mee MEE-wo`},{pl: `Proszę bardzo.`, nl: `Alstublieft / graag gedaan.`, ipa: `PRO-she BAR-dzo`},{pl: `Nic nie szkodzi.`, nl: `Geen probleem.`, ipa: `niets nye SHKO-dzi`}], grammar: `“Przepraszam” gebruik je voor sorry én om aandacht te vragen. “Proszę bardzo” kan betekenen “hier alstublieft” of “graag gedaan”. Poolse beleefdheid is vaak formeel, dus “pan” en “pani” zijn nuttig in bijna elke publieke situatie.`, practice: [`Vraag of een stoel vrij is.`,`Vraag of hier de rij is.`,`Bedank iemand voor hulp.`,`Reageer met “geen probleem”.`,`Oefen “pan”, “pani” en “państwo”.`]},{day: 28, title: `Korte gesprekken met locals`, title_native: `Krótkie rozmowy z mieszkańcami`, focus: `In een park of café in Poznań voer je een kort vriendelijk gesprek. Je leert praten over waar je vandaan komt, waarom je reist en wat je leuk vindt aan Polen.`, vocab: [{pl: `mieszkaniec`, nl: `inwoner`, ipa: `myesh-KA-nyets`},{pl: `miasto`, nl: `stad`, ipa: `MYAS-to`},{pl: `podróż`, nl: `reis`, ipa: `PO-droosh`},{pl: `wakacje`, nl: `vakantie`, ipa: `va-KA-tsye`},{pl: `praca`, nl: `werk`, ipa: `PRA-tsa`},{pl: `ładnie`, nl: `mooi`, ipa: `WAD-nye`},{pl: `spokojnie`, nl: `rustig`, ipa: `spo-KOY-nye`},{pl: `ciekawie`, nl: `interessant`, ipa: `che-KA-vye`},{pl: `pierwszy raz`, nl: `eerste keer`, ipa: `PYERF-shi ras`},{pl: `Polska`, nl: `Polen`, ipa: `POL-ska`}], phrases: [{pl: `Jestem pierwszy raz w Polsce.`, nl: `Ik ben voor het eerst in Polen.`, ipa: `YES-tem PYERF-shi ras f POL-sce`},{pl: `Bardzo podoba mi się Polska.`, nl: `Ik vind Polen erg mooi.`, ipa: `BAR-dzo po-DO-ba mee shen POL-ska`},{pl: `To miasto jest bardzo ładne.`, nl: `Deze stad is erg mooi.`, ipa: `to MYAS-to yest BAR-dzo WAD-ne`},{pl: `Jestem tutaj na wakacjach.`, nl: `Ik ben hier op vakantie.`, ipa: `YES-tem TOO-tay na va-KA-tsyah`},{pl: `Podróżuję sam.`, nl: `Ik reis alleen, man spreekt.`, ipa: `po-dro-ZHOO-ye sam`},{pl: `Podróżuję sama.`, nl: `Ik reis alleen, vrouw spreekt.`, ipa: `po-dro-ZHOO-ye SA-ma`}], grammar: `“Podoba mi się...” betekent “ik vind ... mooi/leuk”. Letterlijk is het anders gebouwd dan in het Nederlands, maar als vaste zin is het heel nuttig. “Bardzo podoba mi się Polska” klinkt natuurlijk en vriendelijk.`, practice: [`Zeg dat je voor het eerst in Polen bent.`,`Zeg dat je hier op vakantie bent.`,`Zeg dat je Polen mooi vindt.`,`Kies “sam” of “sama” voor alleen reizen.`,`Geef een compliment over een stad.`]},{day: 29, title: `Plannen wijzigen`, title_native: `Zmiana planów`, focus: `Tijdens reizen loopt niet alles volgens plan. Je leert zeggen dat je te laat bent, iets wilt annuleren, verzetten of opnieuw boeken.`, vocab: [{pl: `plan`, nl: `plan`, ipa: `plan`},{pl: `zmiana`, nl: `verandering`, ipa: `ZMYA-na`},{pl: `anulować`, nl: `annuleren`, ipa: `a-noo-LO-vatsj`},{pl: `przełożyć`, nl: `verzetten`, ipa: `pshe-WO-zhits`},{pl: `spóźniony`, nl: `te laat, mannelijke vorm`, ipa: `spoozh-NYO-ni`},{pl: `spóźniona`, nl: `te laat, vrouwelijke vorm`, ipa: `spoozh-NYO-na`},{pl: `wcześniej`, nl: `eerder`, ipa: `FCZESH-nyey`},{pl: `później`, nl: `later`, ipa: `POOZH-nyey`},{pl: `rezerwować`, nl: `reserveren`, ipa: `re-zer-VO-vatsj`},{pl: `potwierdzić`, nl: `bevestigen`, ipa: `pot-FYER-dzits`}], phrases: [{pl: `Jestem spóźniony.`, nl: `Ik ben te laat, man spreekt.`, ipa: `YES-tem spoozh-NYO-ni`},{pl: `Jestem spóźniona.`, nl: `Ik ben te laat, vrouw spreekt.`, ipa: `YES-tem spoozh-NYO-na`},{pl: `Chcę anulować rezerwację.`, nl: `Ik wil de reservering annuleren.`, ipa: `htse a-noo-LO-vatsj re-zer-VA-tsye`},{pl: `Czy mogę przełożyć spotkanie?`, nl: `Kan ik de afspraak verzetten?`, ipa: `tshi MO-ge pshe-WO-zhits spot-KA-nye`},{pl: `Czy mogę zarezerwować na później?`, nl: `Kan ik voor later reserveren?`, ipa: `tshi MO-ge za-re-zer-VO-vatsj na POOZH-nyey`},{pl: `Chcę potwierdzić rezerwację.`, nl: `Ik wil de reservering bevestigen.`, ipa: `htse pot-FYER-dzits re-zer-VA-tsye`}], grammar: `“Chcę” betekent “ik wil”. Daarna kun je een werkwoord gebruiken: “Chcę anulować”, “Chcę potwierdzić”. Dit is direct, maar normaal in praktische situaties zoals hotel, restaurant of vervoer.`, practice: [`Zeg dat je te laat bent.`,`Zeg dat je een reservering wilt annuleren.`,`Vraag of je een afspraak kunt verzetten.`,`Vraag of je voor later kunt reserveren.`,`Zeg dat je een reservering wilt bevestigen.`]},{day: 30, title: `Reisgesprekken combineren`, title_native: `Łączenie rozmów w podróży`, focus: `Vandaag combineer je alles: begroeten, vragen, bestellen, hulp zoeken en sociaal reageren. Je bent klaar voor echte korte gesprekken in Poolse steden.`, vocab: [{pl: `rozumiem`, nl: `ik begrijp`, ipa: `ro-ZOO-myem`},{pl: `nie rozumiem`, nl: `ik begrijp het niet`, ipa: `nye ro-ZOO-myem`},{pl: `powoli`, nl: `langzaam`, ipa: `po-VO-lee`},{pl: `jeszcze raz`, nl: `nog een keer`, ipa: `YESH-che ras`},{pl: `po angielsku`, nl: `in het Engels`, ipa: `po an-GYEL-skoo`},{pl: `po polsku`, nl: `in het Pools`, ipa: `po POL-skoo`},{pl: `łatwe`, nl: `makkelijk`, ipa: `WAT-ve`},{pl: `trudne`, nl: `moeilijk`, ipa: `TROOD-ne`},{pl: `ważne`, nl: `belangrijk`, ipa: `VAZH-ne`},{pl: `gotowy`, nl: `klaar, mannelijke vorm`, ipa: `go-TO-vi`}], phrases: [{pl: `Nie rozumiem.`, nl: `Ik begrijp het niet.`, ipa: `nye ro-ZOO-myem`},{pl: `Proszę mówić powoli.`, nl: `Spreekt u langzaam, alstublieft.`, ipa: `PRO-she MOO-veech po-VO-lee`},{pl: `Jeszcze raz, proszę.`, nl: `Nog een keer, alstublieft.`, ipa: `YESH-che ras PRO-she`},{pl: `Czy mówi pan po angielsku?`, nl: `Spreekt u Engels?`, ipa: `tshi MOO-vee pan po an-GYEL-skoo`},{pl: `Trochę mówię po polsku.`, nl: `Ik spreek een beetje Pools.`, ipa: `TRO-he MOO-vye po POL-skoo`},{pl: `Jestem gotowy.`, nl: `Ik ben klaar, man spreekt.`, ipa: `YES-tem go-TO-vi`}], grammar: `Zinnen zoals “Nie rozumiem”, “Powoli, proszę” en “Jeszcze raz, proszę” zijn je veiligheidsnet. Ze houden het gesprek gaande zonder dat je alles hoeft te begrijpen. Zeg ook gerust “Trochę mówię po polsku”; veel mensen waarderen de moeite.`, practice: [`Zeg dat je het niet begrijpt.`,`Vraag iemand langzaam te spreken.`,`Vraag om herhaling.`,`Vraag of iemand Engels spreekt.`,`Maak een kort gesprek van vijf zinnen met woorden uit deze cursus.`]}];

var CONVERSATIONS_NL_PL = [{id: 1, title: `Bestellen in een café`, scene: `Je bent in een klein café in Krakau, vlak bij het marktplein. Je wilt koffie, water en iets zoets bestellen. De medewerker begint het gesprek.`, lines: [{who: `them`, pl: `Dzień dobry, co podać?`, nl: `Goedendag, wat mag het zijn?`},{who: `you`, pl: `Dzień dobry, poproszę kawę.`, nl: `Goedendag, ik wil graag koffie.`},{who: `them`, pl: `Małą czy dużą?`, nl: `Klein of groot?`},{who: `you`, pl: `Dużą, proszę.`, nl: `Groot, alstublieft.`},{who: `them`, pl: `Z mlekiem czy bez mleka?`, nl: `Met melk of zonder melk?`},{who: `you`, pl: `Z mlekiem, bez cukru.`, nl: `Met melk, zonder suiker.`},{who: `them`, pl: `Coś jeszcze?`, nl: `Verder nog iets?`},{who: `you`, pl: `Tak, poproszę wodę niegazowaną i ciastko.`, nl: `Ja, ik wil graag plat water en een gebakje.`},{who: `them`, pl: `Na miejscu czy na wynos?`, nl: `Hier of om mee te nemen?`},{who: `you`, pl: `Na miejscu, proszę.`, nl: `Hier, alstublieft.`},{who: `them`, pl: `To będzie dwadzieścia złotych.`, nl: `Dat wordt twintig zloty.`},{who: `you`, pl: `Proszę bardzo, dziękuję.`, nl: `Alstublieft, dank u.`}]},{id: 2, title: `Inchecken in een hotel`, scene: `Je komt aan in een hotel in Gdańsk na een lange treinreis. Je hebt een reservering en wilt weten of ontbijt inbegrepen is. De receptionist spreekt je als eerste aan.`, lines: [{who: `them`, pl: `Dobry wieczór, witamy w hotelu.`, nl: `Goedenavond, welkom in het hotel.`},{who: `you`, pl: `Dobry wieczór, mam rezerwację.`, nl: `Goedenavond, ik heb een reservering.`},{who: `them`, pl: `Na jakie nazwisko?`, nl: `Op welke naam?`},{who: `you`, pl: `Na nazwisko Cannon.`, nl: `Op naam Cannon.`},{who: `them`, pl: `Poproszę paszport.`, nl: `Uw paspoort, alstublieft.`},{who: `you`, pl: `Proszę bardzo.`, nl: `Alstublieft.`},{who: `them`, pl: `Dziękuję, pokój jest na trzecim piętrze.`, nl: `Dank u, de kamer is op de derde verdieping.`},{who: `you`, pl: `Czy jest winda?`, nl: `Is er een lift?`},{who: `them`, pl: `Tak, winda jest po prawej stronie.`, nl: `Ja, de lift is aan de rechterkant.`},{who: `you`, pl: `Czy śniadanie jest w cenie?`, nl: `Is ontbijt inbegrepen?`},{who: `them`, pl: `Tak, śniadanie jest od siódmej.`, nl: `Ja, ontbijt is vanaf zeven uur.`},{who: `you`, pl: `Dziękuję bardzo.`, nl: `Hartelijk dank.`}]},{id: 3, title: `De weg vragen naar het station`, scene: `Je bent in Wrocław en zoekt het treinstation. Je spreekt iemand op straat beleefd aan. Jij begint het gesprek.`, lines: [{who: `you`, pl: `Przepraszam, gdzie jest dworzec?`, nl: `Pardon, waar is het station?`},{who: `them`, pl: `Dworzec jest niedaleko.`, nl: `Het station is niet ver.`},{who: `you`, pl: `Czy mogę iść pieszo?`, nl: `Kan ik te voet gaan?`},{who: `them`, pl: `Tak, proszę iść prosto.`, nl: `Ja, ga rechtdoor.`},{who: `you`, pl: `Potem w prawo czy w lewo?`, nl: `Daarna naar rechts of naar links?`},{who: `them`, pl: `Potem w lewo przy dużej ulicy.`, nl: `Daarna links bij de grote straat.`},{who: `you`, pl: `Czy to daleko?`, nl: `Is het ver?`},{who: `them`, pl: `Nie, około dziesięć minut.`, nl: `Nee, ongeveer tien minuten.`},{who: `you`, pl: `Dziękuję za pomoc.`, nl: `Bedankt voor de hulp.`},{who: `them`, pl: `Proszę bardzo.`, nl: `Graag gedaan.`},{who: `you`, pl: `Do widzenia.`, nl: `Tot ziens.`},{who: `them`, pl: `Do widzenia.`, nl: `Tot ziens.`}]},{id: 4, title: `Uit eten in een restaurant`, scene: `Je gaat eten in een restaurant in Lublin. Je wilt een tafel, vraagt om een aanbeveling en bestelt pierogi. De ober begint het gesprek.`, lines: [{who: `them`, pl: `Dzień dobry, dla ilu osób?`, nl: `Goedendag, voor hoeveel personen?`},{who: `you`, pl: `Dzień dobry, stolik dla dwóch osób, proszę.`, nl: `Goedendag, een tafel voor twee personen, alstublieft.`},{who: `them`, pl: `Proszę, tutaj jest menu.`, nl: `Alstublieft, hier is het menu.`},{who: `you`, pl: `Dziękuję, co pan poleca?`, nl: `Dank u, wat raadt u aan?`},{who: `them`, pl: `Polecam pierogi i zupę.`, nl: `Ik raad pierogi en soep aan.`},{who: `you`, pl: `Poproszę pierogi i wodę niegazowaną.`, nl: `Ik wil graag pierogi en plat water.`},{who: `them`, pl: `Czy coś jeszcze?`, nl: `Verder nog iets?`},{who: `you`, pl: `Czy to jest ostre?`, nl: `Is dit pittig?`},{who: `them`, pl: `Nie, to jest łagodne.`, nl: `Nee, het is mild.`},{who: `you`, pl: `Dobrze, dziękuję.`, nl: `Goed, dank u.`},{who: `them`, pl: `Smacznego.`, nl: `Eet smakelijk.`},{who: `you`, pl: `Dziękuję.`, nl: `Dank u.`}]},{id: 5, title: `Een tramkaartje kopen`, scene: `Je bent in Warschau en wilt met de tram naar het centrum. Je koopt een kaartje en controleert of je de juiste richting hebt. De medewerker begint het gesprek.`, lines: [{who: `them`, pl: `Dzień dobry, w czym mogę pomóc?`, nl: `Goedendag, waarmee kan ik helpen?`},{who: `you`, pl: `Poproszę jeden bilet na tramwaj.`, nl: `Ik wil graag één tramkaartje.`},{who: `them`, pl: `Normalny czy ulgowy?`, nl: `Normaal of korting?`},{who: `you`, pl: `Normalny, proszę.`, nl: `Normaal, alstublieft.`},{who: `them`, pl: `Proszę bardzo.`, nl: `Alstublieft.`},{who: `you`, pl: `Czy ten tramwaj jedzie do centrum?`, nl: `Gaat deze tram naar het centrum?`},{who: `them`, pl: `Tak, proszę wysiąść na trzecim przystanku.`, nl: `Ja, stap uit bij de derde halte.`},{who: `you`, pl: `Gdzie jest przystanek?`, nl: `Waar is de halte?`},{who: `them`, pl: `Tam, po lewej stronie.`, nl: `Daar, aan de linkerkant.`},{who: `you`, pl: `Czy mogę zapłacić kartą?`, nl: `Kan ik met kaart betalen?`},{who: `them`, pl: `Tak, oczywiście.`, nl: `Ja, natuurlijk.`},{who: `you`, pl: `Dziękuję bardzo.`, nl: `Hartelijk dank.`}]},{id: 6, title: `Winkelen voor souvenirs`, scene: `Je bent in een souvenirwinkel in Krakau. Je ziet een T-shirt en wilt de prijs, maat en kleur vragen. De verkoper begint het gesprek.`, lines: [{who: `them`, pl: `Dzień dobry, mogę pomóc?`, nl: `Goedendag, kan ik helpen?`},{who: `you`, pl: `Dzień dobry, ile kosztuje ta koszulka?`, nl: `Goedendag, hoeveel kost dit T-shirt?`},{who: `them`, pl: `Czterdzieści złotych.`, nl: `Veertig zloty.`},{who: `you`, pl: `Czy macie większy rozmiar?`, nl: `Heeft u een grotere maat?`},{who: `them`, pl: `Tak, mamy większy rozmiar.`, nl: `Ja, we hebben een grotere maat.`},{who: `you`, pl: `Czy jest kolor niebieski?`, nl: `Is er een blauwe kleur?`},{who: `them`, pl: `Tak, proszę bardzo.`, nl: `Ja, alstublieft.`},{who: `you`, pl: `Czy mogę przymierzyć?`, nl: `Mag ik het passen?`},{who: `them`, pl: `Oczywiście, przymierzalnia jest tam.`, nl: `Natuurlijk, de paskamer is daar.`},{who: `you`, pl: `Dobrze, dziękuję.`, nl: `Goed, dank u.`},{who: `them`, pl: `Czy bierze pan tę koszulkę?`, nl: `Neemt u dit T-shirt?`},{who: `you`, pl: `Tak, poproszę.`, nl: `Ja, graag.`}]},{id: 7, title: `Bij de apotheek`, scene: `Je bent in Poznań en hebt keelpijn en hoofdpijn. Je gaat naar een apotheek en vraagt om iets eenvoudigs. De apotheker begint het gesprek.`, lines: [{who: `them`, pl: `Dzień dobry, w czym mogę pomóc?`, nl: `Goedendag, waarmee kan ik helpen?`},{who: `you`, pl: `Dzień dobry, boli mnie gardło.`, nl: `Goedendag, ik heb keelpijn.`},{who: `them`, pl: `Czy ma pan gorączkę?`, nl: `Heeft u koorts?`},{who: `you`, pl: `Nie, ale boli mnie głowa.`, nl: `Nee, maar ik heb hoofdpijn.`},{who: `them`, pl: `Czy ma pan alergię?`, nl: `Heeft u een allergie?`},{who: `you`, pl: `Tak, mam alergię na orzechy.`, nl: `Ja, ik ben allergisch voor noten.`},{who: `them`, pl: `Rozumiem, dam coś na ból gardła.`, nl: `Ik begrijp het, ik geef iets tegen keelpijn.`},{who: `you`, pl: `Czy potrzebuję recepty?`, nl: `Heb ik een recept nodig?`},{who: `them`, pl: `Nie, recepta nie jest potrzebna.`, nl: `Nee, een recept is niet nodig.`},{who: `you`, pl: `Ile to kosztuje?`, nl: `Hoeveel kost het?`},{who: `them`, pl: `Piętnaście złotych.`, nl: `Vijftien zloty.`},{who: `you`, pl: `Dziękuję bardzo.`, nl: `Hartelijk dank.`}]},{id: 8, title: `Smalltalk met een local`, scene: `Je zit in een café in Toruń en raakt aan de praat met iemand aan de volgende tafel. Je vertelt dat je voor het eerst in Polen bent. Jij begint het gesprek.`, lines: [{who: `you`, pl: `Przepraszam, czy to miejsce jest wolne?`, nl: `Pardon, is deze plaats vrij?`},{who: `them`, pl: `Tak, proszę.`, nl: `Ja, gaat uw gang.`},{who: `you`, pl: `Dziękuję, jestem pierwszy raz w Polsce.`, nl: `Dank u, ik ben voor het eerst in Polen.`},{who: `them`, pl: `Naprawdę? Jak się panu podoba?`, nl: `Echt? Hoe bevalt het u?`},{who: `you`, pl: `Bardzo podoba mi się Polska.`, nl: `Ik vind Polen erg mooi.`},{who: `them`, pl: `Które miasto pan lubi najbardziej?`, nl: `Welke stad vindt u het leukst?`},{who: `you`, pl: `Kraków jest piękny, ale Toruń też jest ciekawy.`, nl: `Krakau is mooi, maar Toruń is ook interessant.`},{who: `them`, pl: `Czy mówi pan po polsku?`, nl: `Spreekt u Pools?`},{who: `you`, pl: `Trochę mówię po polsku.`, nl: `Ik spreek een beetje Pools.`},{who: `them`, pl: `Bardzo dobrze.`, nl: `Heel goed.`},{who: `you`, pl: `Proszę mówić powoli.`, nl: `Spreekt u langzaam, alstublieft.`},{who: `them`, pl: `Oczywiście, nie ma problemu.`, nl: `Natuurlijk, geen probleem.`}]}];